import{_ as e,o as s,c as o,a4 as t}from"./chunks/framework.CDpUjPX_.js";const h=JSON.parse('{"title":"KAAS em 5 Minutos","description":"","frontmatter":{},"headers":[],"relativePath":"agentes/quick-start.md","filePath":"agentes/quick-start.md"}'),r={name:"agentes/quick-start.md"};function i(n,a,d,p,l,c){return s(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="kaas-em-5-minutos" tabindex="-1">KAAS em 5 Minutos <a class="header-anchor" href="#kaas-em-5-minutos" aria-label="Permalink to &quot;KAAS em 5 Minutos&quot;">​</a></h1><p>Guia rapido para quem nunca usou o sistema de agentes IA do Kubex.</p><hr><h2 id="o-que-voce-precisa-saber" tabindex="-1">O que voce precisa saber <a class="header-anchor" href="#o-que-voce-precisa-saber" aria-label="Permalink to &quot;O que voce precisa saber&quot;">​</a></h2><p>O KAAS usa o <strong>Claude Code</strong> (extensao do VSCode) como runtime. Cada agente e um prompt especializado que voce cola numa sessao do Claude Code. O agente le suas instrucoes (persona, regras, workflows) e executa tarefas autonomamente.</p><p>O sistema opera em modo <strong>hibrido</strong>: 8 agentes automaticos via scheduler + 3 sob demanda pelo CEO.</p><hr><h2 id="pre-requisitos" tabindex="-1">Pre-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pre-requisitos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Verificacao</th></tr></thead><tbody><tr><td>VSCode com Claude Code</td><td>Extensao instalada e autenticada</td></tr><tr><td>Docker Desktop rodando</td><td><code>docker ps</code> funciona</td></tr><tr><td>Projeto Kubex aberto</td><td><code>d:\\Kubex</code> no VSCode</td></tr><tr><td>AIOX-Core instalado</td><td>Pasta <code>.aiox-core/</code> existe</td></tr><tr><td>API key configurada</td><td><code>ANTHROPIC_API_KEY</code> no <code>.env</code></td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .aiox-core/personas/kubex/</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Deve listar 11 arquivos .md</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                         # Containers kubex-* rodando</span></span></code></pre></div><hr><h2 id="seu-primeiro-agente-3-minutos" tabindex="-1">Seu primeiro agente (3 minutos) <a class="header-anchor" href="#seu-primeiro-agente-3-minutos" aria-label="Permalink to &quot;Seu primeiro agente (3 minutos)&quot;">​</a></h2><p>O <strong>SRE Agent</strong> (Polaris) e ideal para comecar — somente leitura, nao modifica nada.</p><h3 id="passo-1-abrir-claude-code" tabindex="-1">Passo 1: Abrir Claude Code <a class="header-anchor" href="#passo-1-abrir-claude-code" aria-label="Permalink to &quot;Passo 1: Abrir Claude Code&quot;">​</a></h3><p>No VSCode: <code>Ctrl+Shift+P</code> → &quot;Claude Code: Open&quot;</p><h3 id="passo-2-colar-o-prompt" tabindex="-1">Passo 2: Colar o prompt <a class="header-anchor" href="#passo-2-colar-o-prompt" aria-label="Permalink to &quot;Passo 2: Colar o prompt&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Leia e assuma a persona em .aiox-core/personas/kubex/sre-agent.md</span></span>
<span class="line"><span>Siga as regras em .aiox-core/rules/kubex-operations.md e .claude/rules/agent-operations.md</span></span>
<span class="line"><span>Consulte a documentacao em docs/ para contexto.</span></span>
<span class="line"><span>Execute o workflow em .aiox-core/workflows/kubex/continuous-monitoring.md</span></span>
<span class="line"><span>Gere o relatorio no formato especificado no workflow.</span></span></code></pre></div><h3 id="passo-3-observar" tabindex="-1">Passo 3: Observar <a class="header-anchor" href="#passo-3-observar" aria-label="Permalink to &quot;Passo 3: Observar&quot;">​</a></h3><p>O agente vai rodar health checks nos 27 motores, verificar circuit breakers, checar Sentinel, e gerar um relatorio.</p><h3 id="passo-4-revisar" tabindex="-1">Passo 4: Revisar <a class="header-anchor" href="#passo-4-revisar" aria-label="Permalink to &quot;Passo 4: Revisar&quot;">​</a></h3><p>O agente pede aprovacao antes de qualquer acao que modifique o sistema.</p><hr><h2 id="ordem-recomendada-para-ciclo-completo" tabindex="-1">Ordem recomendada para ciclo completo <a class="header-anchor" href="#ordem-recomendada-para-ciclo-completo" aria-label="Permalink to &quot;Ordem recomendada para ciclo completo&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. SRE Agent (Polaris)      → Diagnosticar estado atual</span></span>
<span class="line"><span>2. QA Agent (Capella)       → Rodar testes, identificar gaps</span></span>
<span class="line"><span>3. Security Agent (Sirius)  → Auditoria de seguranca</span></span>
<span class="line"><span>4. Backend Agent (Altair)   → Corrigir problemas encontrados</span></span>
<span class="line"><span>5. Docs Agent (Aquila)      → Atualizar documentacao</span></span>
<span class="line"><span>6. Director Agent (Vega)    → Gerar relatorio consolidado</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">IMPORTANTE</p><p>Rode cada agente em uma <strong>sessao separada</strong> do Claude Code para manter o contexto isolado.</p></div><hr><h2 id="como-saber-se-deu-certo" tabindex="-1">Como saber se deu certo? <a class="header-anchor" href="#como-saber-se-deu-certo" aria-label="Permalink to &quot;Como saber se deu certo?&quot;">​</a></h2><p>Apos rodar o SRE Agent, voce deve ver um relatorio parecido com:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>=== RELATORIO DE SAUDE — Kubex ===</span></span>
<span class="line"><span>Motores: 24/27 healthy</span></span>
<span class="line"><span>Circuit Breakers: 0 abertos</span></span>
<span class="line"><span>Sentinel: OK</span></span>
<span class="line"><span>Redis: 1.2MB / 256MB | Celery: 4 workers, 0 pendentes</span></span></code></pre></div><hr><h2 id="proximos-passos" tabindex="-1">Proximos passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Proximos passos&quot;">​</a></h2><ul><li>Entenda os fluxos: <a href="./fluxos">Diagramas visuais</a></li><li>Veja exemplos reais: <a href="./exemplos">Sessoes de exemplo</a></li><li>Duvidas: <a href="./faq">FAQ</a></li><li>Guia completo: <a href="./operacao">Operacao dos Agentes</a></li></ul>`,32)])])}const m=e(r,[["render",i]]);export{h as __pageData,m as default};
